# Write a quick program to inspect the MSTest 4.1.0 API via reflection
cd /tmp && mkdir -p api_check && cat > api_check/Program.cs << 'CSHARP'
using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/mstest.testframework/4.1.0/lib/net8.0/MSTest.TestFramework.dll");

// Check TestMethodAttribute
var tma = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.TestMethodAttribute");
Console.WriteLine($"TestMethodAttribute sealed: {tma.IsSealed}");
Console.WriteLine($"TestMethodAttribute methods:");
foreach (var m in tma.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  {m.Name} ({(m.IsVirtual ? "virtual" : "non-virtual")})");

// Check for TestTimeout
var tt = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.TestTimeout");
Console.WriteLine($"\nTestTimeout exists: {tt != null}");

// Check TimeoutAttribute
var ta = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.TimeoutAttribute");
if (ta != null) {
    Console.WriteLine($"TimeoutAttribute constructors:");
    foreach (var c in ta.GetConstructors())
        Console.WriteLine($"  ({string.Join(", ", c.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}

// Look for ITestMethodDecorator or similar
Console.WriteLine("\nTypes containing 'Decorator' or 'Fixture':");
foreach (var t in asm.GetExportedTypes().Where(t => t.Name.Contains("Decorator") || t.Name.Contains("Fixture")))
    Console.WriteLine($"  {t.FullName}");

// Look for anything related to test method extensibility
Console.WriteLine("\nInterfaces:");
foreach (var t in asm.GetExportedTypes().Where(t => t.IsInterface))
    Console.WriteLine($"  {t.FullName}");
CSHARP

